def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    epsilon = 1e-9
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / (cap + epsilon)
        base_score = 0.0
        adjustment_factor = 1.0
        for j in range(1, 10):
            if j % 4 == 0:
                adjustment_factor *= 1.15
            elif j % 5 == 0:
                adjustment_factor *= 0.85
            if ratio < (0.05 * j):
                base_score += (j ** 3) * (1 - ratio) * adjustment_factor
            else:
                base_score += j * np.cos(ratio * j * np.pi / 4) * adjustment_factor
            if cap % (j + 1) == 0:
                base_score *= 1.07
            else:
                base_score *= 0.93
        if cap > 5 * item:
            for k in range(1, 5):
                diff = cap - item * k
                if diff % 3 == 0:
                    base_score += np.tanh(diff / (k + 1)) * k
                else:
                    base_score -= np.exp(-abs(diff) / (k + 2)) * (k + 1)
        if ratio < 0.5:
            priority = -base_score / (np.sqrt(cap + 1) + epsilon)
        else:
            priority = -base_score * np.log1p(cap + 1)
        if cap % 2 == 0 and item % 1 < 0.5:
            priority *= 0.9
        elif cap % 2 == 1 and item % 1 >= 0.5:
            priority *= 1.1
        if priority == 0:
            priority = -epsilon
        priorities[i] = priority
    return priorities
